def generate_4digit_with_pattern(first=None, second=None, third=None, fourth=None):
    """Generate all 4-digit numbers matching a specified digit pattern.

    Key insight: Using None as wildcard allows generating numbers that match
    specific positions while iterating over all possibilities for others.

    Args:
        first, second, third, fourth: digit (0-9) for each position, or None for wildcard

    Yields:
        All 4-digit integers matching the pattern (leading digit won't be 0).
    """
    first_digits = [first] if first is not None else range(1, 10)
    second_digits = [second] if second is not None else range(10)
    third_digits = [third] if third is not None else range(10)
    fourth_digits = [fourth] if fourth is not None else range(10)

    for d1 in first_digits:
        if d1 == 0:
            continue
        for d2 in second_digits:
            for d3 in third_digits:
                for d4 in fourth_digits:
                    yield d1 * 1000 + d2 * 100 + d3 * 10 + d4

def max_subset_forbidden_differences(n, forbidden_diffs):
    """Find maximum subset of {1,...,n} with no pairs having forbidden differences.

    Key insight: Uses iterative DP with state encoding which of the last k positions
    are included, where k = max(forbidden_diffs). State is a bitmask where bit j
    indicates whether position (current - j) was included. For each position, we can
    either skip it (always valid) or include it (if no forbidden neighbor was included).

    Time complexity: O(n * 2^k) where k = max(forbidden_diffs).

    Args:
        n: upper bound of the set {1, 2, ..., n}
        forbidden_diffs: set of positive integers representing forbidden pairwise differences

    Returns:
        Maximum size of a subset with no two elements differing by a forbidden value.
    """
    if n <= 0:
        return 0

    forbidden = set(forbidden_diffs)
    max_diff = max(forbidden) if forbidden else 0
    state_bits = max_diff + 1
    mask = (1 << state_bits) - 1

    # dp[state] = max achievable size with current state
    # state bit j = 1 means position (current_pos - j - 1) was included
    dp = {0: 0}

    for pos in range(1, n + 1):
        new_dp = {}
        for state, size in dp.items():
            # Option 1: don't include pos
            new_state = (state << 1) & mask
            if new_state not in new_dp or new_dp[new_state] < size:
                new_dp[new_state] = size

            # Option 2: include pos (if allowed)
            can_include = True
            for diff in forbidden:
                if diff < pos:
                    # Check if pos - diff was included
                    # Position pos - diff corresponds to bit (diff - 1) after shift
                    bit_idx = diff - 1
                    if (state >> bit_idx) & 1:
                        can_include = False
                        break

            if can_include:
                new_state = ((state << 1) | 1) & mask
                if new_state not in new_dp or new_dp[new_state] < size + 1:
                    new_dp[new_state] = size + 1

        dp = new_dp

    return max(dp.values())

