def max_independent_set_graph(nodes, edges):
    """Find a maximum independent set in a graph using exhaustive search.

    Key insight: An independent set is a set of vertices with no edges between them.
    For small graphs, we can enumerate all subsets in decreasing order of size
    and return the first valid one found.

    Args:
        nodes: iterable of node identifiers
        edges: iterable of (node1, node2) pairs representing undirected edges

    Returns:
        Tuple (size, independent_set) where independent_set is a tuple of nodes.
    """
    from itertools import combinations

    nodes = list(nodes)
    edges = list(edges)
    edge_set = set()
    for u, v in edges:
        edge_set.add((min(u, v), max(u, v)))

    def is_independent(subset):
        subset_set = set(subset)
        for u, v in edge_set:
            if u in subset_set and v in subset_set:
                return False
        return True

    for size in range(len(nodes), 0, -1):
        for subset in combinations(nodes, size):
            if is_independent(subset):
                return size, subset

    return 0, ()

def sum_of_squares_solutions(target, range_a, range_b=None):
    """Find all pairs (a, b) where a² + b² equals target, with a, b in given ranges.

    Key insight: Enumerate all possible pairs and check if their squares sum to target.
    For symmetric ranges, solutions come in pairs (a, b) and (b, a) unless a = b.

    Args:
        target: the desired sum of squares (non-negative integer)
        range_a: tuple (start, end) or single integer n meaning range(1, n+1)
        range_b: tuple (start, end) or single integer; defaults to range_a if None

    Returns:
        List of tuples (a, b) where a² + b² = target
    """
    if isinstance(range_a, int):
        range_a = (1, range_a + 1)
    if range_b is None:
        range_b = range_a
    elif isinstance(range_b, int):
        range_b = (1, range_b + 1)

    solutions = []
    for a in range(range_a[0], range_a[1]):
        for b in range(range_b[0], range_b[1]):
            if a * a + b * b == target:
                solutions.append((a, b))
    return solutions
